insert into public.event_quizzes (event_id, slug, num, phase, title, sub, hero_img, difficulty, questions, status, sort, published)
values (
  'vm-2026', 'gruppespill-3', '14', 'Gruppespill omgang 3',
  'Omgang 3 — gruppene avgjort', 'Siste gruppekamper: Dembélé herjer mot Norge, Ecuador feller Tyskland — 24.–26. juni.', 'vm-gruppespill-1', 'middels',
  '[{"category": "Resultat", "q": "Hva ble resultatet da Norge møtte Frankrike i den avgjørende gruppe I-kampen 26. juni?", "options": ["1–4 til Frankrike", "2–2", "0–3 til Frankrike", "1–2 til Frankrike"], "correct": 0, "explanation": "Frankrike vant 1–4 i Foxborough; begge lag var alt klare for sluttspillet, men franskmennene tok førsteplassen i gruppe I."}, {"category": "Stjerner", "q": "Ousmane Dembélé herjet mot Norge. Hva presterte han?", "options": ["Hat trick i første omgang", "Ett mål og to målgivende", "To straffemål", "Et selvmål og ett mål"], "correct": 0, "explanation": "Dembélé scoret tre ganger før pause (7., 20. og 32. minutt); Désiré Doué la på til 4–1 på overtid."}, {"category": "Norge", "q": "Hvem scoret Norges mål mot Frankrike?", "options": ["Erling Haaland", "Alexander Sørloth", "Thelo Aasgaard", "Martin Ødegaard"], "correct": 2, "explanation": "Aasgaard reduserte til 1–2 i det 21. minutt, kort etter Dembélés andre scoring."}, {"category": "Kuriosa", "q": "Hvilken rolle spilte Erling Haaland i kampen mot Frankrike?", "options": ["Han satt på benken og ble ikke brukt", "Han ble byttet ut i pausen", "Han fikk rødt kort", "Han scoret Norges mål"], "correct": 0, "explanation": "Norge gjorde mange endringer i den avgjørende kampen, og Haaland var ubrukt innbytter i 1–4-tapet."}, {"category": "Resultat", "q": "Hvordan endte Senegals siste gruppespillkamp, mot Irak?", "options": ["1–0 til Senegal", "5–0 til Senegal", "2–2", "3–0 til Senegal"], "correct": 1, "explanation": "Senegal vant 5–0 i Toronto mot et Irak som spilte med ti mann etter et tidlig rødt kort."}, {"category": "Målscorer", "q": "Hvem ble tomålshelt for Senegal mot Irak — med to langskudd fra innbytterbenken?", "options": ["Pape Gueye", "Iliman Ndiaye", "Sadio Mané", "Ismaila Sarr"], "correct": 0, "explanation": "Innbytter Pape Gueye curlet inn to scoringer (59. og 71.); Diarra, Sarr og Ndiaye sto for de andre."}, {"category": "Drama", "q": "Tyskland tapte 1–2 i sin siste gruppekamp. Hvem sto for sjokket?", "options": ["Ecuador", "Sør-Korea", "Elfenbenskysten", "Sveits"], "correct": 0, "explanation": "Ecuador snudde kampen i New Jersey — Gonzalo Plata avgjorde i det 77. minutt etter at Leroy Sané hadde sendt Tyskland i ledelsen tidlig."}, {"category": "Resultat", "q": "Belgia slo New Zealand klart i sin siste gruppekamp. Hva ble sifrene?", "options": ["5–1 til Belgia", "3–3", "4–0 til Belgia", "2–0 til Belgia"], "correct": 0, "explanation": "Belgia vant 5–1 i Vancouver; Leandro Trossard scoret to, og De Bruyne, Lukaku og Saelemaekers ett hver."}, {"category": "Målscorer", "q": "Spania slo Uruguay 1–0. Hvem scoret det eneste målet?", "options": ["Álex Baena", "Lamine Yamal", "Pedri", "Mikel Oyarzabal"], "correct": 0, "explanation": "Baena avgjorde i det 42. minutt etter en tabbe av Uruguays keeper Fernando Muslera."}, {"category": "Gruppe A", "q": "Mexico vant 3–0 i sin siste gruppekamp. Hvem var motstanderen?", "options": ["Sør-Korea", "Tsjekkia", "Polen", "Kroatia"], "correct": 1, "explanation": "Mexico slo Tsjekkia 3–0 med mål av Chávez, Quiñones og Fidalgo, og vant alle tre gruppekampene i gruppe A."}]'::jsonb, 'locked', 14, true
)
on conflict (event_id, slug) do update set
  num=excluded.num, phase=excluded.phase, title=excluded.title, sub=excluded.sub,
  hero_img=excluded.hero_img, difficulty=excluded.difficulty, questions=excluded.questions,
  status=excluded.status, sort=excluded.sort, published=excluded.published;
